# Category: path_traversal

import os

class FileExplorerAPI:
    def __init__(self, root):
        self._root = os.path.normpath(os.path.join(root))

    def listdir(self, path):
        return [f for f in os.listdir(os.path.normpath(os.path.join(self._root, path))) if not os.path.isdir(
            os.path.normpath(os.path.join(self._root, path, f)))]

    def download_file(self, path):
        return open(os.path.normpath(os.path.join(self._root, path)), 'rb').read()

    def getinfo(self, path):
        return os.stat(os.path.normpath(os.path.join(self._root, path)))

def main():
    root = '/Users/jason/Desktop'
    api = FileExplorerAPI(root)
    print('Listing files in', root)
    for f in api.listdir('.'):
        print(f)

    print('Downloading file', 'file1')
    with open('/Users/jason/Desktop/file1', 'wb') as f:
        f.write(api.download_file('file1'))

if __name__ == '__main__':
    main()